   CSS Custom Properties
   =========================== */
:root {
  /* Primary */
  --color-purple-600: hsl(246, 80%, 60%);

  /* Category colors */
  --color-work:      hsl(15, 100%, 70%);
  --color-play:      hsl(195, 74%, 62%);
  --color-study:     hsl(348, 100%, 68%);
  --color-exercise:  hsl(145, 58%, 55%);
  --color-social:    hsl(264, 64%, 52%);
  --color-self-care: hsl(43, 84%, 65%);

  /* Neutral */
  --color-navy-950:  hsl(226, 43%, 10%);
  --color-navy-900:  hsl(235, 46%, 20%);
  --color-purple-500: hsl(235, 45%, 61%);
  --color-navy-200:  hsl(236, 100%, 87%);

  /* Card hover */
  --color-card-hover: hsl(235, 46%, 30%);

  /* Typography */
  --font-family: 'Rubik', sans-serif;
  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
}

/* ===========================
   Reset & Base
   =========================== */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 18px;
}

body {
  font-family: var(--font-family);
  font-weight: var(--font-weight-regular);
  background-color: var(--color-navy-950);
  color: white;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 2rem 1.5rem;
}

/* ===========================
   Dashboard Layout
   =========================== */
.dashboard {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1.5rem;
  width: 100%;
  max-width: 1110px;
}

@media (min-width: 768px) {
  .dashboard {
    grid-template-columns: repeat(2, 1fr);
    align-items: start;
  }
}

@media (min-width: 1100px) {
  .dashboard {
    grid-template-columns: repeat(4, 1fr);
    align-items: start;
  }
}

/* ===========================
   Profile Card
   =========================== */
.profile-card {
  background-color: var(--color-navy-900);
  border-radius: 1rem;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

@media (min-width: 768px) {
  .profile-card {
    grid-row: 1 / 3;
  }
}

@media (min-width: 1100px) {
  .profile-card {
    grid-row: 1 / 3;
    grid-column: 1 / 2;
  }
}

.profile-info {
  background-color: var(--color-purple-600);
  border-radius: 1rem;
  padding: 2rem;
  display: flex;
  align-items: center;
  gap: 1.25rem;
  flex: 1;
}

@media (min-width: 768px) {
  .profile-info {
    flex-direction: column;
    align-items: flex-start;
    padding: 2.5rem 2rem;
  }
}

.profile-avatar {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  border: 3px solid white;
  flex-shrink: 0;
}

@media (min-width: 768px) {
  .profile-avatar {
    width: 78px;
    height: 78px;
    margin-bottom: 2.5rem;
  }
}

.profile-label {
  font-size: 0.833rem;
  font-weight: var(--font-weight-regular);
  color: var(--color-navy-200);
  margin-bottom: 0.25rem;
}

.profile-name {
  font-size: 1.5rem;
  font-weight: var(--font-weight-light);
  line-height: 1.2;
