{"content": "/**
 * Time Tracking Dashboard - script.js
 *
 * Fetches data from data.json, renders activity cards,
 * and handles Daily / Weekly / Monthly view switching.
 */

(function () {
  'use strict';

  // ── State ────────────────────────────────────────────────────────────────
  let currentTimeframe = 'weekly';
  let activities = [];

  // Category → icon filename mapping
  const ICON_MAP = {
    'Work':      'icon-work.svg',
    'Play':      'icon-play.svg',
    'Study':     'icon-study.svg',
    'Exercise':  'icon-exercise.svg',
    'Social':    'icon-social.svg',
    'Self Care': 'icon-self-care.svg',
  };

  // Timeframe → "previous" label prefix
  const PREV_LABEL = {
    daily:   'Yesterday',
    weekly:  'Last Week',
    monthly: 'Last Month',
  };

  // ── Helpers ───────────────────────────────────────────────────────────────
  /**
   * Format hours: "1hr" or "5hrs"
   */
  function formatHours(n) {
    return n === 1 ? '1hr' : `${n}hrs`;
  }

  /**
   * Slug for icon path (also used as data-category attribute value)
   */
  function iconPath(title) {
    const filename = ICON_MAP[title] || `icon-${title.toLowerCase().replace(/\s+/g, '-')}.svg`;
    return `./time-tracking-dashboard-main/images/${filename}`;
  }

  // ── Render ────────────────────────────────────────────────────────────────
  function renderCards() {
    const grid = document.getElementById('cards-grid');
    if (!grid) return;

    grid.innerHTML = '';

    activities.forEach((activity) => {
      const { title, timeframes } = activity;
      const data = timeframes[currentTimeframe];
      if (!data) return;

      const prevLabel = PREV_LABEL[currentTimeframe];
      const card = document.createElement('div');
      card.className = 'activity-card';
      card.setAttribute('data-category', title);
      card.setAttribute('data-testid', `card-${title.toLowerCase().replace(/\s+/g, '-')}`);

      card.innerHTML = `
        <div class="card-top" aria-hidden="true">
          <img
            class="card-icon"
            src="${iconPath(title)}"
            alt=""
            aria-hidden="true"
          >
        </div>
        <div class="card-body">
          <div class="card-header">
            <h2 class="card-title">${title}</h2>
            <button
              class="card-ellipsis"
              aria-label="More options for ${title}"
            >
              <img
                src="./time-tracking-dashboard-main/images/icon-ellipsis.svg"
                alt=""
                width="21"
                height="5"
              >
            </button>
          </div>
          <div class="card-stats">
            <p class="card-current" data-current>${formatHours(data.current)}</p>
            <p class="card-previous" data-previous>${prevLabel} - ${formatHours(data.previous)}</p>
          </div>
        </div>
      `;

      grid.appendChild(card);
    });
  }

  /**
   * Update existing cards in-place (swap text only, no DOM teardown)
   */
  function updateCards() {
    const prevLabel = PREV_LABEL[currentTimeframe];
    const cards = document.querySelectorAll('.activity-card');

    cards.forEach((card) => {
      const title = card.getAttribute('data-category');
      const activity = activities.find((a) => a.title === title);
      if (!activity) return;

      const data = activity.timeframes[currentTimeframe];
      if (!data) return;

      const currentEl = card.querySelector('[data-current]');
      const previousEl = card.querySelector('[data-previous]');

      if (currentEl)  currentEl.textContent  = formatHours(data.current);
      if (previousEl) previousEl.textContent = `${prevLabel} - ${formatHours(data.previous)}`;
    });
  }

  // ── Timeframe switcher ────────────────────────────────────────────────────
  function initSwitcher() {
    const buttons = document.querySelectorAll('.timeframe-btn');
    buttons.forEach((btn) => {
      btn.addEventListener('click', () => {
        const tf = btn.dataset.timeframe;
        if (tf === currentTimeframe) return;

        // Update active state
        buttons.forEach((b) => b.classList.remove('active'));
        btn.classList.add('active');

        currentTimeframe = tf;
        updateCards();
      });
    });
  }

  // ── Bootstrap ─────────────────────────────────────────────────────────────
  async function init() {
    try {
      const response = await fetch('./data.json');
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      activities = await response.json();
    } catch (err) {
