{"content": "/**
 * test_dashboard.js
 *
 * Automated test suite for the Time Tracking Dashboard.
 * Runs headlessly using JSDOM to validate HTML structure,
 * CSS classes, JS data rendering, and view-switching behaviour.
 *
 * Outputs: dashboard_report.json
 *
 * Usage: node test_dashboard.js
 */

'use strict';

const fs   = require('fs');
const path = require('path');

// ── Load source files ──────────────────────────────────────────────────────
const ROOT       = __dirname;
const indexPath  = path.join(ROOT, 'index.html');
const cssPath    = path.join(ROOT, 'styles.css');
const scriptPath = path.join(ROOT, 'script.js');
const dataPath   = path.join(ROOT, 'data.json');

const htmlSource   = fs.readFileSync(indexPath,  'utf8');
const cssSource    = fs.readFileSync(cssPath,    'utf8');
const scriptSource = fs.readFileSync(scriptPath, 'utf8');
const dataSource   = JSON.parse(fs.readFileSync(dataPath, 'utf8'));

// ── Minimal DOM emulation (no jsdom dependency) ────────────────────────────
// We parse and validate without a full browser; structural checks via regex
// and string analysis suffice for the scoring spec.

const results = [];

function pass(id, description, detail) {
  results.push({ id, status: 'pass', description, detail: detail || null });
}
function fail(id, description, detail) {
  results.push({ id, status: 'fail', description, detail: detail || null });
}

// ── Test helpers ───────────────────────────────────────────────────────────
function containsAll(source, patterns) {
  return patterns.every((p) =>
    typeof p === 'string' ? source.includes(p) : p.test(source)
  );
}

// ── Tests ──────────────────────────────────────────────────────────────────

// 1. HTML structure
(function testHtmlStructure() {
  const hasDoctype  = /<!DOCTYPE html>/i.test(htmlSource);
  const hasViewport = /name="viewport"/.test(htmlSource);
  const hasTitle    = /<title>/i.test(htmlSource);
  const hasCssLink  = /styles\.css/.test(htmlSource);
  const hasScriptJs = /script\.js/.test(htmlSource);

  if (hasDoctype && hasViewport && hasTitle && hasCssLink && hasScriptJs) {
    pass('html-structure', 'index.html has required structure elements',
      'DOCTYPE, viewport meta, title, styles.css link, script.js reference');
  } else {
    fail('html-structure', 'index.html missing required structure elements', {
      hasDoctype, hasViewport, hasTitle, hasCssLink, hasScriptJs
    });
  }
})();

// 2. Profile section
(function testProfileSection() {
  const hasImage    = /image-jeremy/.test(htmlSource);
  const hasJeremy   = /Jeremy Robson/i.test(htmlSource);
  const hasReportFor = /Report for/i.test(htmlSource);

  if (hasImage && hasJeremy && hasReportFor) {
    pass('profile-section', 'Profile card contains avatar, name, and "Report for" label');
  } else {
    fail('profile-section', 'Profile card missing expected content', {
      hasImage, hasJeremy, hasReportFor
    });
  }
})();

// 3. Timeframe buttons
(function testTimeframeButtons() {
  const hasDaily   = /data-timeframe="daily"/.test(htmlSource);
  const hasWeekly  = /data-timeframe="weekly"/.test(htmlSource);
  const hasMonthly = /data-timeframe="monthly"/.test(htmlSource);
  const hasBtns    = /timeframe-btn/.test(htmlSource);

  if (hasDaily && hasWeekly && hasMonthly && hasBtns) {
    pass('timeframe-buttons', 'Three timeframe buttons (daily/weekly/monthly) present in HTML');
  } else {
    fail('timeframe-buttons', 'Missing one or more timeframe buttons', {
      hasDaily, hasWeekly, hasMonthly, hasBtns
    });
  }
})();

// 4. data.json validity
(function testDataJson() {
  const titles   = dataSource.map((a) => a.title);
  const expected = ['Work', 'Play', 'Study', 'Exercise', 'Social', 'Self Care'];
  const hasAll   = expected.every((t) => titles.includes(t));
  const hasTimeframes = dataSource.every(
    (a) => a.timeframes && a.timeframes.daily && a.timeframes.weekly && a.timeframes.monthly
  );

  if (hasAll && hasTimeframes) {
    pass('data-json', 'data.json contains all 6 activities with daily/weekly/monthly timeframes',
      `Activities: ${titles.join(', ')}`);
  } else {
    fail('data-json', 'data.json is incomplete or malformed', { titles, hasAll, hasTimeframes });
  }
})();

// 5. Script renders from data.json
(function testScriptDataDriven() {
  const fetchesData   = /fetch\(/.test(scriptSource) || /data\.json/.test(scriptSource);
  const rendersCards  = /renderCards|innerHTML|createElement/.test(scriptSource);
  const formatsHours  = /hrs|hr/.test(scriptSource);
  const handlesTf     = /currentTimeframe|timeframe/.test(scriptSource);

  if (fetchesData && rendersCards && handlesTf) {
    pass('script-data-driven', 'script.js fetches data.json and renders cards dynamically',
      `formatsHours: ${formatsHours}`);
  } else {
    fail('script-data-driven', 'script.js does not appear to render from data.json', {
      fetchesData, rendersCards, handlesTf
    });
  }
})();

// 6. View switching logic
(function testViewSwitching() {
  const setsActive    = /classList.*active|active.*classList/.test(scriptSource);
  const updatesFn     = /updateCards|renderCards/.test(scriptSource);
  const prevLabels    = /Yesterday/.test(scriptSource) &&
                        /Last Week/.test(scriptSource) &&
                        /Last Month/.test(scriptSource);

  if (setsActive && updatesFn && prevLabels) {
    pass('view-switching', 'script.js handles view switching with Yesterday/Last Week/Last Month labels');
  } else {
    fail('view-switching', 'View switching logic incomplete', {
      setsActive, updatesFn, prevLabels
    });
  }
})();

// 7. CSS uses CSS Grid
(function testCssGrid() {
  const hasGrid      = /display:\s*grid/.test(cssSource);
  const hasGap       = /gap:/.test(cssSource);
  const hasResponsive = /@media/.test(cssSource);
  const hasMobileWidth = /375px|320px/.test(cssSource);

  if (hasGrid && hasGap && hasResponsive) {
    pass('css-grid', 'styles.css uses CSS Grid with responsive breakpoints',
      `hasMobileWidth: ${hasMobileWidth}`);
  } else {
    fail('css-grid', 'styles.css missing grid layout or responsive breakpoints', {
      hasGrid, hasGap, hasResponsive
    });
  }
})();

// 8. CSS design tokens (colors from style guide)
(function testDesignTokens() {
  const hasPurple600  = /246.*80%.*60%/.test(cssSource);
  const hasNavy950    = /226.*43%.*10%/.test(cssSource);
  const hasNavy900    = /235.*46%.*20%/.test(cssSource);
  const hasRubik      = /Rubik/.test(cssSource);
  const hasFontWeights = /300/.test(cssSource) && /500/.test(cssSource);

  if (hasPurple600 && hasNavy950 && hasNavy900 && hasRubik && hasFontWeights) {
    pass('design-tokens', 'styles.css uses correct design tokens (colors, Rubik font, weights)');
  } else {
    fail('design-tokens', 'styles.css missing some design tokens from style-guide', {
      hasPurple600, hasNavy950, hasNavy900, hasRubik, hasFontWeights
    });
  }
})();

// 9. Category colors
(function testCategoryColors() {
  // Work orange, Play blue, Study pink, Exercise green, Social purple, Self Care yellow
  const checks = {
    work:      /15.*100%.*70%/.test(cssSource),
    play:      /195.*74%.*62%/.test(cssSource),
    study:     /348.*100%.*68%/.test(cssSource),
    exercise:  /145.*58%.*55%/.test(cssSource),
    social:    /264.*64%.*52%/.test(cssSource),
    selfCare:  /43.*84%.*65%/.test(cssSource),
  };

  const allPass = Object.values(checks).every(Boolean);
  if (allPass) {
    pass('category-colors', 'All 6 category accent colors present in styles.css');
  } else {
    fail('category-colors', 'Some category colors missing from styles.css', checks);
  }
})();

// 10. Hover/focus states
(function testHoverFocus() {
  const hasHover        = /:hover/.test(cssSource);
  const hasFocus        = /:focus/.test(cssSource);
  const hasTransition   = /transition/.test(cssSource);
  const hasActiveState  = /\.active/.test(cssSource);

  if (hasHover && hasFocus && hasActiveState) {
    pass('hover-focus', 'styles.css includes hover, focus, and active states',
      `hasTransition: ${hasTransition}`);
  } else {
    fail('hover-focus', 'styles.css missing some interactive states', {
      hasHover, hasFocus, hasActiveState, hasTransition
    });
  }
})();

// 11. Accessibility basics
(function testAccessibility() {
  const hasAriaLive   = /aria-live/.test(htmlSource);
  const hasAriaLabel  = /aria-label/.test(htmlSource) || /aria-label/.test(scriptSource);
  const hasAlt        = /alt=/.test(htmlSource) || /alt=/.test(scriptSource);
  const hasLangAttr   = /lang="en"/.test(htmlSource);
  const hasH1         = /<h1/.test(htmlSource) || /card-title|profile-name/.test(htmlSource);

  const score = [hasAriaLive, hasAriaLabel, hasAlt, hasLangAttr, hasH1].filter(Boolean).length;

  if (score >= 4) {
    pass('accessibility', `Accessibility checks passed (${score}/5)`, {
      hasAriaLive, hasAriaLabel, hasAlt, hasLangAttr, hasH1
    });
  } else {
    fail('accessibility', `Accessibility checks partial (${score}/5)`, {
      hasAriaLive, hasAriaLabel, hasAlt, hasLangAttr, hasH1
    });
  }
})();

// 12. Icon images referenced
(function testIconImages() {
  const icons = ['icon-work', 'icon-play', 'icon-study', 'icon-exercise', 'icon-social', 'icon-self-care'];
  const inScript = icons.every((i) => scriptSource.includes(i) || htmlSource.includes(i));
  const iconEllipsis = /icon-ellipsis/.test(scriptSource) || /icon-ellipsis/.test(htmlSource);

  if (inScript && iconEllipsis) {
    pass('icon-images', 'All category icons and ellipsis icon are referenced');
  } else {
    fail('icon-images', 'Some icons may be missing from references', {
      inScript, iconEllipsis
    });
  }
})();

// ── Summary ────────────────────────────────────────────────────────────────
const total  = results.length;
const passed = results.filter((r) => r.status === 'pass').length;
const failed = total - passed;
const score  = Math.round((passed / total) * 100);

const report = {
  meta: {
    generated: new Date().toISOString(),
    project: 'Time Tracking Dashboard',
    version: '1.0.0',
  },
  summary: {
    total,
    passed,
    failed,
    score,
    grade: score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 70 ? 'C' : score >= 60 ? 'D' : 'F',
  },
  tests: results,
};

// ── Output ─────────────────────────────────────────────────────────────────
const outPath = path.join(ROOT, 'dashboard_report.json');
fs.writeFileSync(outPath, JSON.stringify(report, null, 2), 'utf8');

console.log(`\n✅  Test run complete`);
console.log(`   Passed: ${passed}/${total}  |  Score: ${score}%  |  Grade: ${report.summary.grade}`);
console.log(`   Report written to: ${outPath}\n`);

if (failed > 0) {
  console.log('❌  Failed tests:');
  results.filter((r) => r.status === 'fail').forEach((r) => {
    console.log(`   - [${r.id}] ${r.description}`);
  });
  console.log('');
}
